class Solution {
    public int maxSubstrings(String word) {
        int n = word.length();
        int ans = 0;
        for (int i = 0; i < n - 3; i++) {
            for (char c = 'a'; c <= 'z'; c++) {
                if (word.charAt(i) == c && word.charAt(i + 3) == c) {
                    int j = i + 1;
                    while (j < n && word.charAt(j) == word.charAt(i) && word.charAt(j + 1) == word.charAt(i + 1)) {
                        j += 2;
                    }
                    if (j - i > 4) {
                        ans++;
                    }
                }
            }
        }
        return ans;
    }
}
